// Runs in the browser; no dependencies needed
const es = new EventSource('/events');

// Fired once when the connection opens
es.onopen = () => console.log('Connection established');

// Default listener for unnamed events (type == 'message')
es.onmessage = (event) => {
  console.log('Received:', event.data);
  document.getElementById('output').textContent += event.data + '\n';
};

// Named event listener - matches `event: done` frames
es.addEventListener('done', (event) => {
  console.log('Stream finished:', event.data);
  es.close();  // stop the connection
});

// Error / reconnect handler
es.onerror = (err) => {
  if (es.readyState === EventSource.CLOSED) {
    console.error('Connection closed permanently');
  } else {
    console.warn('Reconnecting...');
    // Browser auto-reconnects; Last-Event-ID is sent automatically
  }
};
